use std::borrow::Cow;

fn abs_all(input: &mut Cow<[i32]>) {
    for i in 0..input.len() {
        let v = input[i];
        if v < 0 {
            // Clone only if we need to mutate
            input.to_mut()[i] = -v;
        }
    }
}

fn main() {
    // No clone needed - all values are positive
    let slice = [1, 2, 3];
    let mut input = Cow::from(&slice[..]);
    abs_all(&mut input);
    println!("No negatives: {:?}", input);

    // Clone needed - has negative values
    let slice2 = [-1, 2, -3];
    let mut input2 = Cow::from(&slice2[..]);
    abs_all(&mut input2);
    println!("Had negatives: {:?}", input2);

    // Already owned - no clone needed
    let mut input3 = Cow::from(vec![-1, 2, -3]);
    abs_all(&mut input3);
    println!("Already owned: {:?}", input3);
}

